sys_script_client.messages:
Now Assist has a plan for solving {0}. {1}
Now Assist has a plan for solving this record. {0}
View plan

sys_script_client.script:
function onLoad() {
    var ga = new GlideAjax('sn_aia.AIAConversationUtilsAjax');
    ga.addParam('sysparm_name', 'hasNonInteractedAgenticConversationForTargetRecord');
    ga.addParam('sysparm_target_record_id', g_form.getUniqueValue());
    ga.getXMLAnswer(function(convId) {
        if (convId) {
            var isWorkspace = typeof GwtMessage === 'function' ? false : true;
            var message = '';
            var viewPlanBtn = '';
            var viewPlanMsg = '';
            var number = g_form.getValue('number');
            if (isWorkspace) {
                viewPlanMsg = getMessage("View plan");
                viewPlanBtn = `<now-button label="${viewPlanMsg}" bare=true onClick="(function(e){e.target.dispatch('OPEN_UTILITY_MENU', { id: 'nowAssist', pin: false, additionalData: { conversationId: '${convId}' } }); })(event);">${viewPlanMsg}</now-button>`;
                if (number) {
                    message = getMessage("Now Assist has a plan for solving {0}. {1}", [number, viewPlanBtn]);
                } else {
                    message = getMessage("Now Assist has a plan for solving this record. {0}", viewPlanBtn);
                }
            } else {
                var gwt = new GwtMessage();
                viewPlanMsg = gwt.getMessage("View plan");

                const topHref = getTopWindow?.()?.top?.location?.href || "";
                const isFullClassicUI = topHref.includes("/nav/ui/classic/");
                if (isFullClassicUI) {
                    viewPlanBtn = `<a href="#" onclick="CustomEvent.fireTop('nowassist:open_utility_menu', { id: 'nowAssist', pin: false, additionalData: { conversationId: '${convId}' } });">${viewPlanMsg}</a>`;
                } else {
                    // Convert current URL into Classic UI format and open in new tab
                    const baseUrl = getTopWindow()?.location.origin;
                    const pathAndQuery = getTopWindow()?.location.pathname + getTopWindow()?.location.search;
                    const classicUrl = `${baseUrl}/now/nav/ui/classic/params/target${pathAndQuery}`;
                    viewPlanBtn = `
                        <a href="#" onclick="(function(){
                            const newTab = window.open('${classicUrl}', '_blank');
                            // Wait for the new tab to load before firing the event
                            const interval = setInterval(() => {
                                try {
                                    newTab.CustomEvent.fireTop('nowassist:open_utility_menu', { id: 'nowAssist', pin: false, additionalData: { conversationId: '${convId}' } });
                                    clearInterval(interval);
                                } catch (e) {
                                    // keep waiting until CustomEvent is ready
                                }
                            }, 500);
                        })(); return false;"> ${viewPlanMsg} </a>`;
                }
                if (number) {
                    message = gwt.getMessage("Now Assist has a plan for solving {0}. {1} ", number, viewPlanBtn);
                } else {
                    message = gwt.getMessage("Now Assist has a plan for solving this record. {0}", viewPlanBtn);
                }
            }
            g_form.addSuggestionMessage(message);
        }
    });
}
